{
  "executive_summary": "Zero-downtime migration of the Order Management domain from MongoDB to PostgreSQL using a phased Strangler Fig approach with dual-write, shadow-read verification, and incremental cutover. The architecture introduces a Data Access Abstraction Layer (DAAL) to decouple application code from storage, a Change Data Capture (CDC) pipeline for backfill and ongoing sync, and a verification harness to guarantee data consistency before cutover. At 200 writes/min, the system has comfortable headroom for dual-write overhead. The 8M document backfill is estimated at 4-8 hours depending on document complexity and transformation logic.",

  "architecture": {
    "components": [
      {
        "name": "Data Access Abstraction Layer (DAAL)",
        "responsibility": "Repository interface that abstracts storage backend. Application code calls DAAL; DAAL routes to MongoDB, PostgreSQL, or both depending on migration phase. This is the single point where read/write routing decisions are made.",
        "boundaries": "Owns all read/write routing logic and feature flags. Does NOT own data transformation. Exposes domain-oriented repository interfaces (OrderRepository, PaymentRepository) — consumers never know which DB backs them."
      },
      {
        "name": "Schema Transformer",
        "responsibility": "Converts MongoDB document shapes to PostgreSQL relational schema. Handles denormalization-to-normalization mapping: flattening embedded subdocuments into rows, extracting arrays into junction tables, mapping BSON types to PG types.",
        "boundaries": "Pure data transformation. No I/O. Stateless. Used by both the CDC pipeline and the DAAL dual-write path."
      },
      {
        "name": "CDC Backfill Pipeline",
        "responsibility": "Performs historical migration of 8M documents using MongoDB Change Streams (for real-time tail) and a batch scanner (for historical data). Writes transformed records to PostgreSQL. Maintains a high-water mark for resumability.",
        "boundaries": "Owns backfill orchestration and progress tracking. Reads from MongoDB, writes to PostgreSQL. Does NOT serve application traffic. Runs as a separate process/job."
      },
      {
        "name": "Verification Harness",
        "responsibility": "Shadow-reads from both databases on a percentage of production traffic, compares results, and logs discrepancies. Provides a dashboard of consistency metrics. Migration cannot advance phases until verification passes threshold (99.99% consistency).",
        "boundaries": "Read-only against both databases. Owns consistency metrics and alerting. Does NOT modify data."
      },
      {
        "name": "Migration Orchestrator",
        "responsibility": "Controls migration phase transitions via feature flags. Phases: (1) MongoDB-primary + CDC backfill, (2) Dual-write + shadow-read, (3) PostgreSQL-primary + MongoDB-fallback, (4) PostgreSQL-only. Provides rollback capability at each phase.",
        "boundaries": "Owns phase state machine and feature flag configuration. Does NOT own data flow — delegates to DAAL and CDC pipeline."
      },
      {
        "name": "PostgreSQL Schema (Target)",
        "responsibility": "Normalized relational schema for orders, order_line_items, payments, payment_events. Enforces FK constraints, supports ACID transactions, optimized for join-heavy reporting queries.",
        "boundaries": "Owns data integrity via constraints and triggers. Schema versioned via migration tool (e.g., Flyway/Alembic)."
      }
    ],
    "interfaces": [
      {
        "from": "Order Service (Application)",
        "to": "Data Access Abstraction Layer",
        "contract": "OrderRepository.create(order), .findById(id), .update(id, changes), .findByCustomer(customerId, filters). PaymentRepository with similar CRUD + query methods. All return domain objects, never raw DB records.",
        "coupling_type": "loose — interface-based, storage-agnostic"
      },
      {
        "from": "Data Access Abstraction Layer",
        "to": "MongoDB",
        "contract": "Direct MongoDB driver calls via existing data access code. Read/write routing controlled by migration phase flag.",
        "coupling_type": "tight to MongoDB driver — but isolated within DAAL"
      },
      {
        "from": "Data Access Abstraction Layer",
        "to": "PostgreSQL",
        "contract": "SQL via ORM or query builder. Schema Transformer used for writes. Parameterized queries for reads.",
        "coupling_type": "tight to PG driver — but isolated within DAAL"
      },
      {
        "from": "CDC Backfill Pipeline",
        "to": "MongoDB",
        "contract": "MongoDB Change Streams for real-time events. Collection scan with _id cursor for batch backfill. Resume token stored externally.",
        "coupling_type": "tight to MongoDB oplog — acceptable for migration tooling"
      },
      {
        "from": "CDC Backfill Pipeline",
        "to": "PostgreSQL",
        "contract": "Batch INSERT with ON CONFLICT DO UPDATE (upsert). Uses same Schema Transformer as DAAL.",
        "coupling_type": "tight to PG — acceptable for migration tooling"
      },
      {
        "from": "Verification Harness",
        "to": "Data Access Abstraction Layer",
        "contract": "Subscribes to a percentage of read operations. Executes same query against both backends. Compares serialized domain objects.",
        "coupling_type": "loose — observer pattern, no impact on primary data path"
      },
      {
        "from": "Migration Orchestrator",
        "to": "Data Access Abstraction Layer",
        "contract": "Sets migration phase enum: MONGO_PRIMARY | DUAL_WRITE | PG_PRIMARY | PG_ONLY. DAAL reads this flag on each operation.",
        "coupling_type": "loose — feature flag / config-based"
      }
    ],
    "data_flow": "Phase 1 (Backfill): Application writes to MongoDB via DAAL. CDC pipeline tails MongoDB change stream AND scans historical documents, transforms via Schema Transformer, upserts into PostgreSQL. Phase 2 (Dual-Write): DAAL writes to MongoDB first (primary), then synchronously writes to PostgreSQL. Reads still from MongoDB. Verification Harness shadow-reads from PG on 10→50→100% of reads, comparing results. Phase 3 (PG Primary): DAAL writes to PostgreSQL first (primary, in transaction), then async-writes to MongoDB (fallback). Reads from PostgreSQL. MongoDB kept warm for rollback. Phase 4 (Cutover): MongoDB writes stopped. MongoDB data retained read-only for 30 days, then decommissioned. DAAL simplified to PG-only path.",
    "patterns_used": [
      {
        "pattern": "Strangler Fig",
        "rationale": "Incrementally migrates traffic from MongoDB to PostgreSQL without big-bang cutover. Each phase is independently verifiable and reversible. Industry-proven for zero-downtime migrations."
      },
      {
        "pattern": "Change Data Capture (CDC)",
        "rationale": "MongoDB Change Streams provide a reliable, resumable event stream for backfilling historical data while capturing ongoing changes. Eliminates the need to stop writes during backfill."
      },
      {
        "pattern": "Repository Pattern (DAAL)",
        "rationale": "Abstracts storage backend behind domain-oriented interfaces. Application code is unaware of migration. Enables clean removal of MongoDB code post-migration."
      },
      {
        "pattern": "Shadow Read / Dark Launch",
        "rationale": "Verifies PostgreSQL correctness under real production load without impacting users. Discrepancies caught before cutover, not after."
      },
      {
        "pattern": "Feature Flag Phased Rollout",
        "rationale": "Each migration phase controlled by a flag, enabling instant rollback. Decouples deployment from activation."
      },
      {
        "pattern": "Idempotent Writes (Upsert)",
        "rationale": "Both CDC pipeline and dual-write path use upserts keyed on order ID. Safe for retries, reprocessing, and at-least-once delivery semantics."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Order Management",
        "classification": "core",
        "aggregates": [
          "Order (root: order_id; entities: OrderLineItem; values: ShippingAddress, OrderStatus, Money)",
          "Payment (root: payment_id; entities: PaymentEvent; values: PaymentMethod, PaymentStatus, Money)"
        ]
      },
      {
        "name": "Migration Infrastructure",
        "classification": "generic",
        "aggregates": [
          "MigrationPhase (root: phase_id; values: PhaseState, ProgressMetrics)",
          "BackfillJob (root: job_id; values: HighWaterMark, ResumeToken)"
        ]
      }
    ],
    "context_map": [
      {
        "upstream": "Order Management",
        "downstream": "Migration Infrastructure",
        "relationship": "Conformist — Migration Infrastructure conforms to Order Management's domain model. It never changes how orders are structured; it only transforms storage representation."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Synchronous dual-write in Phase 2 rather than async replication only",
      "gains": "Guarantees write consistency between both databases. No replication lag window where PG is behind. Simpler correctness verification.",
      "sacrifices": "~5-15ms additional latency per write (PG round-trip). If PG is down, must decide: fail the write or degrade to MongoDB-only. At 200 writes/min this is ~3.3 writes/sec — well within tolerance.",
      "alternatives_considered": [
        "Async-only replication via CDC: lower latency but introduces consistency lag window and more complex verification",
        "Transactional outbox pattern: better reliability but adds significant complexity for a temporary migration phase"
      ]
    },
    {
      "decision": "MongoDB-first writes during Phase 2 (not PG-first)",
      "gains": "Preserves current system-of-record semantics. If PG write fails, MongoDB still has the data — no data loss. Simplifies rollback: just turn off PG writes.",
      "sacrifices": "PG could fall behind if PG errors are silently caught. Requires error monitoring and alerting on PG write failures.",
      "alternatives_considered": [
        "PG-first writes: would make PG the system of record earlier but increases risk — PG schema/perf issues would impact production"
      ]
    },
    {
      "decision": "Single DAAL abstraction rather than separate read/write services",
      "gains": "Simpler topology. One component to configure, monitor, and debug. Appropriate for the team size and 200 writes/min scale.",
      "sacrifices": "Less granular control over read vs write migration phases. Acceptable because the migration is time-bounded.",
      "alternatives_considered": [
        "CQRS with separate read/write models: overkill for migration; useful if reporting needs diverge permanently post-migration"
      ]
    },
    {
      "decision": "Use MongoDB Change Streams over custom application-level event sourcing for backfill",
      "gains": "Change Streams are built into MongoDB 3.6+, resumable, and capture all changes including those from non-application sources (scripts, admin operations). No application code changes needed for backfill.",
      "sacrifices": "Tied to MongoDB replica set. Change stream retention limited by oplog size — must size oplog to cover backfill duration.",
      "alternatives_considered": [
        "Application-level domain events: more portable but requires all write paths to emit events, which may not be true today",
        "mongodump + mongorestore to PG: not viable for zero-downtime"
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "DAAL Repository Interface",
      "evolution_path": "Post-migration, DAAL simplifies to a thin PG-only repository. The interface remains stable — only the implementation changes. Could later support read replicas or caching layers behind the same interface."
    },
    {
      "area": "PostgreSQL Schema",
      "evolution_path": "Start with a schema that mirrors the document structure closely (ease of transformation), then evolve toward a more normalized schema post-migration. Use PG migrations (Flyway/Alembic) to reshape incrementally."
    },
    {
      "area": "Migration Phase Flags",
      "evolution_path": "Phase flags can be granular — per-customer, per-region, or percentage-based. Enables canary migration: migrate 1% of traffic to PG-primary, verify, then ramp."
    },
    {
      "area": "Verification Harness",
      "evolution_path": "Can be repurposed post-migration as a general data quality monitoring tool or integration test framework."
    }
  ],

  "rigidity_points": [
    {
      "area": "Order ID mapping",
      "reason": "MongoDB ObjectIDs must map deterministically to PostgreSQL primary keys. This mapping must be decided once and never changed — all downstream systems, APIs, and external references depend on it. Recommend using the existing MongoDB _id string as the PG primary key (TEXT or UUID if ObjectIDs are convertible) to avoid maintaining a mapping table."
    },
    {
      "area": "Phase ordering",
      "reason": "Phases must execute in sequence: backfill → dual-write → PG-primary → cutover. Skipping phases risks data loss or inconsistency. The state machine must enforce this."
    },
    {
      "area": "Schema Transformer contract",
      "reason": "The MongoDB→PG transformation logic must be identical in the CDC pipeline and the DAAL dual-write path. Any divergence causes data inconsistency. This is a shared kernel and must be a single, tested module."
    }
  ],

  "risks": [
    {
      "risk": "Dual-write inconsistency: MongoDB write succeeds but PG write fails, creating divergence",
      "severity": "critical",
      "mitigation": "On PG write failure during Phase 2: log the failed write to a dead-letter queue, alert ops, and continue with MongoDB as source of truth. A reconciliation job replays failed writes. Phase 3 (PG-primary) only begins when DLQ is empty and verification harness shows 99.99% consistency."
    },
    {
      "risk": "Backfill takes longer than oplog retention, causing a gap in CDC coverage",
      "severity": "high",
      "mitigation": "Pre-calculate backfill duration. Size MongoDB oplog to 2x expected backfill time. Monitor oplog window continuously during backfill. If oplog is at risk, pause and restart backfill from a new snapshot. Alternative: use mongodump snapshot + change stream from snapshot timestamp."
    },
    {
      "risk": "Schema mismatch: MongoDB documents have inconsistent shapes (schemaless) causing PG insert failures",
      "severity": "high",
      "mitigation": "Run a pre-migration schema analysis job: scan all 8M documents, catalog all field variations, null rates, and type inconsistencies. Build Schema Transformer to handle ALL observed variations. Route untransformable documents to a quarantine collection for manual review."
    },
    {
      "risk": "Performance regression: PG queries slower than MongoDB for certain access patterns (e.g., nested document reads that become multi-table JOINs)",
      "severity": "medium",
      "mitigation": "Shadow-read verification in Phase 2 measures latency per query pattern. Add PG indexes informed by actual query patterns. Use JSONB columns for truly polymorphic data that resists normalization. Set latency SLO: PG p99 must be within 2x of MongoDB p99 before proceeding to Phase 3."
    },
    {
      "risk": "Migration duration creep: team gets stuck in dual-write phase indefinitely, paying maintenance cost of two databases",
      "severity": "medium",
      "mitigation": "Set a hard deadline: 8 weeks from Phase 2 start to Phase 4 completion. If blocked, escalate. The DAAL abstraction makes the dual-write cost tolerable but it is NOT a permanent architecture."
    },
    {
      "risk": "Application code assumes MongoDB-specific behaviors (e.g., flexible schema upserts, nested array updates, ObjectID ordering)",
      "severity": "medium",
      "mitigation": "Audit all MongoDB query patterns before starting. Catalog every distinct query shape. Ensure PG equivalents exist. The DAAL must translate semantics, not just syntax."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Execute in 4 phases over 6-8 weeks. Phase 1 (Week 1-2): Design PG schema, build Schema Transformer, build CDC pipeline, start backfill. Phase 2 (Week 3-4): Deploy DAAL with dual-write. Enable shadow-reads. Fix discrepancies. Phase 3 (Week 5-6): Flip to PG-primary once verification threshold met. Keep MongoDB as hot fallback. Phase 4 (Week 7-8): Disable MongoDB writes. Monitor. Decommission MongoDB Order collections after 30-day retention. Start with the riskiest piece: the Schema Transformer. If the document-to-relational mapping has surprises, discover them in Week 1, not Week 5.",
    "files_to_create_or_modify": [
      "src/orders/repositories/order-repository.interface.ts — Define storage-agnostic repository interface",
      "src/orders/repositories/mongo-order-repository.ts — Extract existing MongoDB access into repository implementation",
      "src/orders/repositories/pg-order-repository.ts — New PostgreSQL repository implementation",
      "src/orders/repositories/dual-write-order-repository.ts — DAAL implementation that delegates to both backends based on phase",
      "src/migration/schema-transformer.ts — MongoDB document → PG row transformation logic",
      "src/migration/cdc-pipeline.ts — Change stream consumer + batch backfill orchestrator",
      "src/migration/verification-harness.ts — Shadow-read comparator and metrics",
      "src/migration/migration-orchestrator.ts — Phase state machine and flag management",
      "db/migrations/001_create_orders_schema.sql — PostgreSQL schema: orders, order_line_items, payments, payment_events tables",
      "db/migrations/002_create_indexes.sql — Indexes based on known query patterns",
      "src/migration/reconciliation-job.ts — Replays failed PG writes from dead-letter queue",
      "src/migration/schema-analysis-job.ts — Pre-migration document shape scanner"
    ],
    "patterns_to_follow": "Repository pattern for data access abstraction. Strategy pattern for the DAAL (swap MongoDB/PG/dual-write strategies). State machine for migration phases — enforce valid transitions only. All migration components should be independently deployable and toggled via feature flags. Use database transactions in PG for order + line items + payment writes — this is the whole reason for migrating. Write comprehensive integration tests that run against both MongoDB and PG to verify behavioral parity.",
    "pitfalls_to_avoid": [
      "DO NOT attempt a big-bang migration with a maintenance window — 8M records at 200 writes/min means even minutes of downtime loses data",
      "DO NOT store the MongoDB→PG ID mapping in a separate table — use the same ID in both systems to avoid a translation layer that becomes a single point of failure",
      "DO NOT normalize the PG schema aggressively on day one — start with a shape close to the documents, get the migration done, then refactor the schema",
      "DO NOT skip the schema analysis job — MongoDB's schemaless nature means you WILL find documents with missing fields, wrong types, or unexpected nesting",
      "DO NOT keep dual-write running longer than necessary — it doubles write latency and creates a permanent consistency risk surface",
      "DO NOT use MongoDB transactions during migration to coordinate with PG — cross-database transactions are not possible; accept eventual consistency during the dual-write phase and verify with the harness"
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 82,
    "high_confidence_areas": [
      "Strangler Fig with dual-write is the correct migration pattern for this scale and zero-downtime constraint",
      "200 writes/min is low enough that dual-write latency overhead is negligible",
      "CDC via MongoDB Change Streams is the right backfill mechanism",
      "Repository abstraction (DAAL) is the correct decoupling strategy",
      "Phase ordering and rollback strategy are well-established"
    ],
    "low_confidence_areas": [
      "Document shape heterogeneity — without seeing actual documents, the Schema Transformer complexity is estimated, not known",
      "Existing query patterns — the DAAL translation complexity depends on how MongoDB-specific current queries are (aggregation pipelines, $lookup, array operators)",
      "Downstream consumers — unclear if other services read directly from the MongoDB orders collection, which would require those to be migrated or an ACL added",
      "Current indexing strategy — PG index design depends on actual query patterns not yet audited"
    ],
    "assumptions": [
      "MongoDB is running as a replica set (required for Change Streams)",
      "The Order Management service is the sole writer to the orders collection — no other services write directly",
      "MongoDB ObjectIDs or existing _id values can serve as PostgreSQL primary keys without collision",
      "The team has PostgreSQL operational experience or is willing to invest in it",
      "8M documents are relatively uniform in structure with manageable variation"
    ]
  }
}
